module RefModule (
	input clk,
	input reset,
	output reg [4:0] gray);

	reg [4:0] bin;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
		if (reset) bin <= 5'b00000;
		else bin <= bin + 1;
	end

	always @(bin) begin
		gray = bin ^ (bin >> 1);
		end
endmodule
